const response = $input.first().json;

function severityFor(event) {
  if (event?.data?.decision === 'denied') return 'critical';
  if (event?.type === 'LockerPolicyDecisionEvent' && event?.data?.reasonCode === 'HARD_BLOCKED') return 'critical';
  if (event?.type === 'StaffAuditEvent' && event?.data?.outcome === 'blocked') return 'critical';

  if (['LockerAccessEvent', 'RoomAccessEvent', 'AccessAttempt'].includes(event?.type)) return 'high';
  if (['CleaningTask', 'RoomBooking', 'PresenceEvent'].includes(event?.type)) return 'medium';

  return 'low';
}

const events = Array.isArray(response?.events) ? response.events : [];
const polledAt = response?.lastPolledAt || new Date().toISOString();

return events.map((event) => {
  const data = event?.data || {};
  const severity = severityFor(event);

  const title = `${event.type} - ${data.memberId || data.actorStaffUserId || 'System'}`.slice(0, 200);
  const status = String(data.decision || data.status || data.outcome || 'pending');
  const memberId = data.memberId ? String(data.memberId) : '';
  const lockerId = data.lockerId ? String(data.lockerId) : '';
  const roomId = data.roomId ? String(data.roomId) : '';
  const decision = data.decision ? String(data.decision) : '';
  const denialReason = String(data.denialReasonCode || data.reasonCode || '');
  const rawData = JSON.stringify(data).slice(0, 1800);

  return {
    json: {
      ...event,
      severity,
      polledAt,
      notionPayload: {
        parent: {
          database_id: $env.NOTION_OPERATIONAL_LOG_DB_ID
        },
        properties: {
          Title: {
            title: [{ text: { content: title } }]
          },
          'Event Type': {
            select: { name: String(event.type) }
          },
          Status: {
            select: { name: status }
          },
          Severity: {
            select: { name: severity }
          },
          Timestamp: {
            date: { start: String(event.occurredAt) }
          },
          'Member ID': {
            rich_text: memberId ? [{ text: { content: memberId } }] : []
          },
          'Locker ID': {
            rich_text: lockerId ? [{ text: { content: lockerId } }] : []
          },
          'Room ID': {
            rich_text: roomId ? [{ text: { content: roomId } }] : []
          },
          Decision: {
            rich_text: decision ? [{ text: { content: decision } }] : []
          },
          'Denial Reason': {
            rich_text: denialReason ? [{ text: { content: denialReason } }] : []
          },
          'Raw Data': {
            rich_text: rawData ? [{ text: { content: rawData } }] : []
          },
          'Polled At': {
            date: { start: String(polledAt) }
          }
        }
      }
    }
  };
});

return items
  .filter((item) => item?.json?.severity === 'critical')
  .map((item) => ({
    json: {
      type: item.json.type,
      occurredAt: item.json.occurredAt,
      severity: item.json.severity,
      data: item.json.data
    }
  }));
